function solve(n: number, edges: number[][]): number {
    // Build the graph: original edges and reversed edges (for potential switches)
    const graph: Map<number, [number, number, boolean][]> = new Map();
    const reversedEdges: Map<number, [number, number][]> = new Map();

    for (const [u, v, w] of edges) {
        if (!graph.has(u)) graph.set(u, []);
        graph.get(u)!.push([v, w, false]); // false indicates original edge

        // Store reversed edges for each node (v) that can be reversed from u->v
        if (!reversedEdges.has(v)) reversedEdges.set(v, []);
        reversedEdges.get(v)!.push([u, w]);
    }

    // Priority queue: [cost, node, usedSwitch]
    const heap: [number, number, boolean][] = [];
    heap.push([0, 0, false]);

    // Distance array: dist[node][usedSwitch]
    const dist: number[][] = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] = 0;

    while (heap.length > 0) {
        heap.sort((a, b) => b[0] - a[0]); // Simple sort to simulate min-heap (not optimal for performance)
        const [currentCost, u, usedSwitch] = heap.pop()!;

        if (u === n - 1) {
            return currentCost;
        }

        if (currentCost > dist[u][usedSwitch ? 1 : 0]) {
            continue;
        }

        // Explore original edges
        if (graph.has(u)) {
            for (const [v, w, _] of graph.get(u)!) {
                const newCost = currentCost + w;
                if (newCost < dist[v][usedSwitch ? 1 : 0]) {
                    dist[v][usedSwitch ? 1 : 0] = newCost;
                    heap.push([newCost, v, usedSwitch]);
                }
            }
        }

        // Explore reversed edges if switch hasn't been used yet
        if (!usedSwitch && reversedEdges.has(u)) {
            for (const [v, w] of reversedEdges.get(u)!) {
                const newCost = currentCost + 2 * w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    heap.push([newCost, v, true]);
                }
            }
        }
    }

    const result = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return result === Infinity ? -1 : result;
}
